package com.blissless.tensei.extensionsimport android.content.ClipDataimport android.content.ClipboardManagerimport android.content.Contextimport android.content.Intentimport android.net.Uriimport android.provider.Settingsimport android.widget.Toastimport androidx.activity.compose.BackHandlerimport androidx.compose.foundation.Imageimport androidx.compose.foundation.clickableimport androidx.compose.foundation.layout.*import androidx.compose.foundation.lazy.LazyColumnimport androidx.compose.foundation.lazy.itemsimport androidx.compose.material.icons.Iconsimport androidx.compose.material.icons.filled.Addimport androidx.compose.material.icons.filled.Closeimport androidx.compose.material.icons.filled.ContentCopyimport androidx.compose.material.icons.filled.Infoimport androidx.compose.material.icons.filled.Refreshimport androidx.compose.material3.*import androidx.compose.runtime.*import androidx.compose.ui.Alignmentimport androidx.compose.ui.Modifierimport androidx.compose.ui.graphics.asImageBitmapimport androidx.compose.ui.graphics.painter.BitmapPainterimport androidx.compose.ui.platform.LocalContextimport androidx.lifecycle.compose.LocalLifecycleOwnerimport androidx.compose.ui.text.font.FontWeightimport androidx.compose.ui.text.style.TextOverflowimport androidx.compose.ui.unit.dpimport androidx.core.graphics.drawable.toBitmapimport androidx.lifecycle.Lifecycleimport androidx.lifecycle.LifecycleEventObserverimport androidx.lifecycle.viewmodel.compose.viewModel@OptIn(ExperimentalMaterial3Api::class)@Composablefun ExtensionsScreen(    viewModel: ExtensionsViewModel = viewModel(),    onBrowseChanged: ((Boolean) -> Unit)? = null) {    val uiState by viewModel.uiState.collectAsState()    var repoUrl by remember { mutableStateOf("") }    var selectedRepoUrl by remember { mutableStateOf<String?>(null) }    val installedPackages = uiState.extensions.map { it.packageName }.toSet()    val lifecycleOwner = LocalLifecycleOwner.current    DisposableEffect(lifecycleOwner) {        val observer = LifecycleEventObserver { _, event ->            if (event == Lifecycle.Event.ON_RESUME) {                viewModel.loadExtensions()            }        }        lifecycleOwner.lifecycle.addObserver(observer)        onDispose { lifecycleOwner.lifecycle.removeObserver(observer) }    }    LaunchedEffect(selectedRepoUrl) {        onBrowseChanged?.invoke(selectedRepoUrl != null)    }    BackHandler(enabled = selectedRepoUrl != null) {        selectedRepoUrl = null    }    val selectedRepoState = selectedRepoUrl?.let { url ->        uiState.repos.find { it.url == url }    }    if (selectedRepoState != null) {        ExtensionBrowserScreen(            repoState = selectedRepoState,            installedPackages = installedPackages,            onInstall = { viewModel.installExtension(it) },            onBack = { selectedRepoUrl = null },            onRemoveRepo = { url -> viewModel.removeRepo(url) }        )        return    }    Scaffold(        topBar = {            TopAppBar(                title = { Text("Extensions") },                colors = TopAppBarDefaults.topAppBarColors(                    containerColor = MaterialTheme.colorScheme.surface                ),                actions = {                    IconButton(onClick = { viewModel.loadExtensions() }) {                        Icon(Icons.Default.Refresh, contentDescription = "Refresh")                    }                }            )        }    ) { padding ->        Column(            modifier = Modifier.fillMaxSize().padding(padding)        ) {            Column(                modifier = Modifier.padding(horizontal = 16.dp, vertical = 12.dp),                verticalArrangement = Arrangement.spacedBy(12.dp)            ) {                OutlinedTextField(                    value = repoUrl,                    onValueChange = { repoUrl = it },                    label = { Text("Repo URL") },                    placeholder = { Text("https://example.com/index.json") },                    modifier = Modifier.fillMaxWidth(),                    singleLine = true,                    shape = androidx.compose.foundation.shape.RoundedCornerShape(12.dp),                    colors = OutlinedTextFieldDefaults.colors(                        unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.25f),                        focusedBorderColor = MaterialTheme.colorScheme.primary.copy(alpha = 0.6f),                        unfocusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f),                        focusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f),                    ),                    trailingIcon = {                        IconButton(                            onClick = {                                if (repoUrl.isNotBlank()) {                                    viewModel.addRepo(repoUrl)                                    repoUrl = ""                                }                            }                        ) {                            Icon(Icons.Default.Add, contentDescription = "Add repo")                        }                    }                )            }            LazyColumn(                modifier = Modifier.fillMaxWidth().weight(1f),                contentPadding = PaddingValues(horizontal = 16.dp, vertical = 8.dp),                verticalArrangement = Arrangement.spacedBy(8.dp)            ) {            if (uiState.repos.isNotEmpty()) {                item {                    Text(                        text = "My Repos",                        style = MaterialTheme.typography.titleMedium,                        fontWeight = FontWeight.Bold                    )                }            }            items(uiState.repos, key = { it.url }) { repoState ->                RepoCard(                    repoState = repoState,                    onClick = { selectedRepoUrl = repoState.url },                    onRemoveRepo = { viewModel.removeRepo(repoState.url) }                )            }                item {                    Spacer(modifier = Modifier.height(8.dp))                    Text(                        text = "Installed",                        style = MaterialTheme.typography.titleMedium,                        fontWeight = FontWeight.Bold                    )                }                when {                    uiState.isLoading -> {                        item {                            Box(                                modifier = Modifier.fillMaxWidth(),                                contentAlignment = Alignment.Center                            ) {                                CircularProgressIndicator()                            }                        }                    }                    uiState.error != null -> {                        item {                            Column(                                modifier = Modifier.fillMaxWidth(),                                horizontalAlignment = Alignment.CenterHorizontally                            ) {                                Text(                                    text = uiState.error!!,                                    color = MaterialTheme.colorScheme.error                                )                                Spacer(modifier = Modifier.height(16.dp))                                Button(onClick = { viewModel.loadExtensions() }) {                                    Text("Retry")                                }                            }                        }                    }                    uiState.extensions.isEmpty() && uiState.repos.isEmpty() -> {                        item {                            Column(                                modifier = Modifier                                    .fillMaxWidth()                                    .padding(vertical = 48.dp),                                horizontalAlignment = Alignment.CenterHorizontally                            ) {                                Text(                                    text = "No extensions found",                                    style = MaterialTheme.typography.titleMedium,                                    color = MaterialTheme.colorScheme.onSurfaceVariant                                )                                Spacer(modifier = Modifier.height(8.dp))                                Text(                                    text = "Add a repo above to browse extensions,\nor install Aniyomi/Tachiyomi extension APKs",                                    style = MaterialTheme.typography.bodyMedium,                                    color = MaterialTheme.colorScheme.onSurfaceVariant                                )                            }                        }                    }                    else -> {                        items(uiState.extensions, key = { it.packageName }) { ext ->                            val ctx = LocalContext.current                            InstalledExtensionCard(                                extension = ext,                                onSettings = { openAppSettings(ctx, ext.packageName) },                            )                        }                    }                }            }        }    }}@Composableprivate fun RepoCard(    repoState: RepoState,    onClick: () -> Unit,    onRemoveRepo: () -> Unit) {    var showRemoveDialog by remember { mutableStateOf(false) }    if (showRemoveDialog) {        AlertDialog(            onDismissRequest = { showRemoveDialog = false },            title = { Text("Remove repo?") },            text = {                Text("This will remove ${repoState.repo?.name ?: repoState.url} from your repos.")            },            confirmButton = {                TextButton(                    onClick = {                        showRemoveDialog = false                        onRemoveRepo()                    }                ) {                    Text("Remove", color = MaterialTheme.colorScheme.error)                }            },            dismissButton = {                TextButton(onClick = { showRemoveDialog = false }) {                    Text("Cancel")                }            }        )    }    Card(        modifier = Modifier            .fillMaxWidth()            .clickable(enabled = repoState.repo != null) { onClick() },        colors = CardDefaults.cardColors(            containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)        ),        shape = androidx.compose.foundation.shape.RoundedCornerShape(12.dp)    ) {        Column(            modifier = Modifier.padding(12.dp),            verticalArrangement = Arrangement.spacedBy(4.dp)        ) {            Row(                modifier = Modifier.fillMaxWidth(),                horizontalArrangement = Arrangement.SpaceBetween,                verticalAlignment = Alignment.CenterVertically            ) {                Column(modifier = Modifier.weight(1f)) {                    Text(                        text = repoState.repo?.name ?: repoState.url,                        style = MaterialTheme.typography.titleSmall,                        fontWeight = FontWeight.SemiBold                    )                    val repo = repoState.repo                    if (!repo?.description.isNullOrBlank()) {                        Text(                            text = repo.description,                            style = MaterialTheme.typography.bodySmall,                            color = MaterialTheme.colorScheme.onSurfaceVariant,                            maxLines = 1,                            overflow = TextOverflow.Ellipsis                        )                    }                }                val ctx = LocalContext.current                IconButton(                    onClick = {                        val clipboard = ctx.getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager                        clipboard.setPrimaryClip(ClipData.newPlainText("Repo URL", repoState.url))                        Toast.makeText(ctx, "URL copied", Toast.LENGTH_SHORT).show()                    }                ) {                    Icon(                        Icons.Default.ContentCopy,                        contentDescription = "Copy URL",                        modifier = Modifier.size(18.dp)                    )                }                IconButton(onClick = { showRemoveDialog = true }) {                    Icon(                        Icons.Default.Close,                        contentDescription = "Remove repo",                        modifier = Modifier.size(18.dp)                    )                }            }            repoState.error?.let { error ->                Text(                    text = error,                    color = MaterialTheme.colorScheme.error,                    style = MaterialTheme.typography.bodySmall                )            }            if (repoState.isLoading) {                LinearProgressIndicator(modifier = Modifier.fillMaxWidth())            }            if (repoState.repo != null) {                Row(                    horizontalArrangement = Arrangement.spacedBy(12.dp),                    verticalAlignment = Alignment.CenterVertically                ) {                    Text(                        text = "${repoState.repo.extensions.size} extension(s)",                        style = MaterialTheme.typography.labelSmall,                        color = MaterialTheme.colorScheme.primary                    )                    Spacer(modifier = Modifier.weight(1f))                    Text(                        text = "Browse →",                        style = MaterialTheme.typography.labelSmall,                        color = MaterialTheme.colorScheme.primary                    )                }            }        }    }}private fun openAppSettings(context: android.content.Context, packageName: String) {    val intent = Intent(Settings.ACTION_APPLICATION_DETAILS_SETTINGS).apply {        data = Uri.parse("package:$packageName")        flags = Intent.FLAG_ACTIVITY_NEW_TASK    }    android.widget.Toast.makeText(context, "Opening app settings...", android.widget.Toast.LENGTH_SHORT).show()    context.startActivity(intent)}@Composableprivate fun InstalledExtensionCard(    extension: Extension,    onSettings: () -> Unit,) {    Card(        modifier = Modifier.fillMaxWidth(),        colors = CardDefaults.cardColors(            containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)        ),        shape = androidx.compose.foundation.shape.RoundedCornerShape(12.dp)    ) {        Row(            modifier = Modifier                .fillMaxWidth()                .padding(12.dp),            verticalAlignment = Alignment.CenterVertically,            horizontalArrangement = Arrangement.spacedBy(12.dp)        ) {            val iconBitmap = extension.icon?.toBitmap(64, 64)            if (iconBitmap != null) {                Image(                    painter = BitmapPainter(iconBitmap.asImageBitmap()),                    contentDescription = extension.name,                    modifier = Modifier.size(48.dp)                )            }            Column(                modifier = Modifier                    .weight(1f)                    .clickable(onClick = onSettings),                verticalArrangement = Arrangement.spacedBy(2.dp)            ) {                Text(                    text = extension.name,                    style = MaterialTheme.typography.titleSmall,                    fontWeight = FontWeight.SemiBold,                    maxLines = 1,                    overflow = TextOverflow.Ellipsis                )                Text(                    text = extension.packageName,                    style = MaterialTheme.typography.bodySmall,                    color = MaterialTheme.colorScheme.onSurfaceVariant,                    maxLines = 1,                    overflow = TextOverflow.Ellipsis                )                Row(                    horizontalArrangement = Arrangement.spacedBy(8.dp),                    verticalAlignment = Alignment.CenterVertically                ) {                    Text(                        text = "v${extension.versionName}",                        style = MaterialTheme.typography.labelSmall,                        color = MaterialTheme.colorScheme.primary                    )                    if (extension.isNsfw) {                        Surface(                            color = MaterialTheme.colorScheme.errorContainer,                            shape = MaterialTheme.shapes.small                        ) {                            Text(                                text = "NSFW",                                style = MaterialTheme.typography.labelSmall,                                color = MaterialTheme.colorScheme.onErrorContainer,                                modifier = Modifier.padding(horizontal = 4.dp, vertical = 1.dp)                            )                        }                    }                }            }            IconButton(onClick = onSettings) {                Icon(                    Icons.Default.Info,                    contentDescription = "App info",                    modifier = Modifier.size(20.dp)                )            }        }    }}